b:if.b:skin:
  /*
  -----------------------------------------------
  Blogger Template Style
  Name:         Ultra-Modern Glassmorphism UI
  Author:       Senior Frontend Developer
  -----------------------------------------------*/

  /* -- Blogger Customizer Settings --
  <Variable name="primary.color" description="Brand Primary Color" type="color" default="#3b82f6" value="#3b82f6"/>
  */

  /* ==========================================================================
     1. DESIGN TOKENS (CSS VARIABLES)
     ========================================================================== */
  :root {
    --font-ui: 'Poppins', 'Inter', system-ui, -apple-system, sans-serif;
    --font-text: 'Merriweather', Georgia, serif;
    
    --bg-body: #f8fafc;
    --bg-surface: rgba(255, 255, 255, 0.7);
    --bg-surface-glass: rgba(255, 255, 255, 0.4);
    --bg-surface-hover: rgba(255, 255, 255, 0.9);
    
    --text-main: #0f172a;
    --text-muted: #64748b;
    --text-light: #94a3b8;
    
    --color-primary: $(primary.color);
    --color-primary-hover: #2563eb;
    --color-primary-light: rgba(59, 130, 246, 0.15);
    
    --border-color: rgba(255, 255, 255, 0.5);
    --border-glass: rgba(255, 255, 255, 0.3);
    
    --shadow-sm: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
    --shadow-md: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -2px rgba(0, 0, 0, 0.025);
    --shadow-lg: 0 20px 25px -5px rgba(0, 0, 0, 0.05), 0 10px 10px -5px rgba(0, 0, 0, 0.02);
    --shadow-hover: 0 0 25px rgba(59, 130, 246, 0.4), 0 10px 15px -3px rgba(0, 0, 0, 0.1);
    
    --radius-sm: 12px;
    --radius-md: 16px;
    --radius-lg: 24px;
    --radius-pill: 9999px;
    
    --space-1: 0.25rem;
    --space-2: 0.5rem;
    --space-3: 0.75rem;
    --space-4: 1rem;
    --space-6: 1.5rem;
    --space-8: 2rem;
    --space-12: 3rem;
    --space-16: 4rem;
    --space-24: 6rem;
    
    --smooth: all 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
    --smooth-fast: all 0.2s cubic-bezier(0.25, 0.8, 0.25, 1);
    --smooth-spring: all 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    
    --max-w-container: 1280px;
    --max-w-reading: 720px;
  }

  html[data-theme="dark"] {
    --bg-body: #0f172a;
    --bg-surface: rgba(30, 41, 59, 0.7);
    --bg-surface-glass: rgba(15, 23, 42, 0.5);
    --bg-surface-hover: rgba(51, 65, 85, 0.8);
    --text-main: #f8fafc;
    --text-muted: #cbd5e1;
    --text-light: #64748b;
    --border-color: rgba(255, 255, 255, 0.1);
    --border-glass: rgba(255, 255, 255, 0.05);
    --shadow-sm: 0 4px 6px -1px rgba(0, 0, 0, 0.4);
    --shadow-md: 0 10px 15px -3px rgba(0, 0, 0, 0.4);
    --shadow-lg: 0 20px 25px -5px rgba(0, 0, 0, 0.5);
    --shadow-hover: 0 0 25px rgba(59, 130, 246, 0.5), 0 10px 15px -3px rgba(0, 0, 0, 0.6);
  }

  /* ==========================================================================
     2. CSS RESET AND BASE STYLES
     ========================================================================== */
  *, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }
  
  html {
    scroll-behavior: smooth;
    -webkit-text-size-adjust: 100%;
  }

  body {
    font-family: var(--font-ui);
    background-color: var(--bg-body);
    color: var(--text-main);
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
    transition: background-color 0.4s ease, color 0.4s ease;
    overflow-x: hidden;
    animation: pageLoadFade 1s cubic-bezier(0.25, 0.8, 0.25, 1) forwards;
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-ui);
    font-weight: 700;
    line-height: 1.2;
    color: var(--text-main);
    margin-bottom: var(--space-4);
  }

  a {
    color: var(--color-primary);
    text-decoration: none;
    transition: var(--smooth-fast);
  }
  
  a:hover {
    color: var(--color-primary-hover);
  }

  img {
    max-width: 100%;
    height: auto;
    display: block;
  }

  ul, ol {
    list-style: none;
  }

  button, input {
    font-family: inherit;
    color: inherit;
    border: none;
    outline: none;
    background: transparent;
    cursor: pointer;
  }

  .container {
    width: 100%;
    max-width: var(--max-w-container);
    margin: 0 auto;
    padding: 0 var(--space-6);
  }

  body.no-scroll {
    overflow: hidden;
  }

  /* ==========================================================================
     3. GLOBAL ANIMATIONS AND KEYFRAMES
     ========================================================================== */
  @keyframes pageLoadFade {
    0% { opacity: 0; filter: blur(10px); }
    100% { opacity: 1; filter: blur(0); }
  }

  @keyframes fadeInUp {
    0% { opacity: 0; transform: translateY(30px); }
    100% { opacity: 1; transform: translateY(0); }
  }

  @keyframes shimmer {
    0% { background-position: -1000px 0; }
    100% { background-position: 1000px 0; }
  }

  .skeleton {
    background: linear-gradient(90deg, var(--border-color) 25%, var(--bg-surface-hover) 50%, var(--border-color) 75%);
    background-size: 1000px 100%;
    animation: shimmer 2s infinite linear;
    border-radius: var(--radius-sm);
  }

  .hidden-animate {
    opacity: 0;
    transform: translateY(40px);
    transition: opacity 0.8s cubic-bezier(0.25, 0.8, 0.25, 1), transform 0.8s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    will-change: opacity, transform;
  }
  
  .hidden-animate.is-visible {
    opacity: 1;
    transform: translateY(0);
  }

  .interactive-hover {
    transition: var(--smooth-spring);
    display: inline-block;
  }
  
  .interactive-hover:hover {
    transform: scale(1.05);
    box-shadow: var(--shadow-hover);
  }

  .btn-primary {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: var(--space-3) var(--space-6);
    font-weight: 600;
    font-size: 0.95rem;
    border-radius: var(--radius-pill);
    background-color: var(--color-primary);
    color: #ffffff;
    box-shadow: var(--shadow-md);
    transition: var(--smooth-spring);
  }

  .btn-primary:hover {
    background-color: var(--color-primary-hover);
    transform: translateY(-2px) scale(1.05);
    box-shadow: var(--shadow-hover);
    color: #ffffff;
  }

  /* ==========================================================================
     4. BENTO GRID AND POST CARD LAYOUT
     ========================================================================== */
  .bento-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
    gap: var(--space-8);
    width: 100%;
    padding: var(--space-8) 0;
  }

  @media (min-width: 992px) {
    .bento-grid .post-card:first-child {
      grid-column: span 2;
      grid-row: span 2;
      flex-direction: row;
    }
    .bento-grid .post-card:first-child .post-card-thumb {
      width: 55%;
      aspect-ratio: auto;
    }
    .bento-grid .post-card:first-child .post-card-content {
      width: 45%;
      justify-content: center;
      padding: var(--space-12);
    }
    .bento-grid .post-card:first-child .post-card-title {
      font-size: 2.25rem;
    }
  }

  .post-card {
    display: flex;
    flex-direction: column;
    background-color: var(--bg-surface);
    border-radius: var(--radius-lg);
    border: 1px solid var(--border-glass);
    overflow: hidden;
    box-shadow: var(--shadow-md);
    transition: var(--smooth);
    position: relative;
    transform: translateZ(0);
  }

  .post-card:hover {
    transform: translateY(-8px);
    box-shadow: var(--shadow-hover);
  }

  .post-card-thumb {
    position: relative;
    width: 100%;
    aspect-ratio: 16/10;
    overflow: hidden;
    background-color: var(--bg-surface-hover);
  }

  .post-card-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.6s cubic-bezier(0.25, 0.8, 0.25, 1);
  }

  .post-card:hover .post-card-thumb img {
    transform: scale(1.08);
  }

  .post-card-content {
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    flex-grow: 1;
  }

  .post-card-category {
    position: absolute;
    top: var(--space-4);
    left: var(--space-4);
    background: var(--bg-surface-glass);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    padding: var(--space-1) var(--space-3);
    border-radius: var(--radius-pill);
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--text-main);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    z-index: 2;
    transition: var(--smooth);
    border: 1px solid var(--border-glass);
  }

  .post-card:hover .post-card-category {
    background: var(--color-primary);
    color: #ffffff;
  }

  .post-card-title {
    font-family: var(--font-ui);
    font-size: 1.35rem;
    font-weight: 700;
    color: var(--text-main);
    line-height: 1.3;
    margin-bottom: var(--space-3);
    transition: color 0.3s ease;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .post-card:hover .post-card-title {
    color: var(--color-primary);
  }

  .post-card-excerpt {
    font-family: var(--font-text);
    font-size: 0.95rem;
    color: var(--text-muted);
    margin-bottom: var(--space-6);
    flex-grow: 1;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .post-card-meta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-size: 0.85rem;
    color: var(--text-light);
    font-weight: 500;
    border-top: 1px solid var(--border-color);
    padding-top: var(--space-4);
    margin-top: auto;
  }

  .meta-author {
    display: flex;
    align-items: center;
    gap: var(--space-2);
    color: var(--text-main);
  }

  .meta-author img {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    object-fit: cover;
  }

  /* ==========================================================================
     5. HEADER AND GLASSMORPHISM NAVBAR
     ========================================================================== */
  .site-header {
    position: sticky;
    top: 0;
    z-index: 100;
    background-color: var(--bg-surface-glass);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border-bottom: 1px solid var(--border-glass);
    transition: transform 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
  }
  
  .site-header.headroom--hidden {
    transform: translateY(-100%);
  }

  .header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 80px;
  }

  .header-logo {
    display: flex;
    align-items: center;
    z-index: 101;
  }
  
  .header-logo img {
    max-height: 36px;
  }
  
  .header-logo .title {
    font-size: 1.5rem;
    font-weight: 700;
    color: var(--text-main);
    letter-spacing: -0.02em;
    margin: 0;
  }

  .desktop-nav {
    display: none;
  }
  
  @media (min-width: 992px) {
    .desktop-nav {
      display: flex;
      align-items: center;
      gap: var(--space-8);
    }
  }

  .desktop-nav ul {
    display: flex;
    gap: var(--space-6);
  }

  .desktop-nav a {
    font-weight: 600;
    font-size: 0.95rem;
    color: var(--text-muted);
    transition: var(--smooth-fast);
  }

  .desktop-nav a:hover {
    color: var(--color-primary);
  }

  .header-actions {
    display: flex;
    align-items: center;
    gap: var(--space-2);
  }

  .search-wrapper {
    position: relative;
    display: flex;
    align-items: center;
  }

  .search-form {
    display: flex;
    align-items: center;
    background: var(--bg-surface-hover);
    border-radius: var(--radius-pill);
    width: 44px;
    height: 44px;
    overflow: hidden;
    transition: width 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    border: 1px solid transparent;
  }

  .search-form.is-expanded {
    width: 240px;
    box-shadow: var(--shadow-sm);
    border-color: var(--border-color);
  }

  .search-input {
    width: 100%;
    height: 100%;
    border: none;
    background: transparent;
    padding: 0 var(--space-3) 0 0;
    font-size: 0.95rem;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.3s ease;
  }

  .search-form.is-expanded .search-input {
    opacity: 1;
    pointer-events: auto;
    padding-left: var(--space-4);
  }

  .search-btn {
    width: 44px;
    height: 44px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    border-radius: 50%;
    color: var(--text-main);
    transition: var(--smooth-fast);
  }

  .search-btn:hover {
    color: var(--color-primary);
  }

  .search-btn svg {
    width: 20px;
    height: 20px;
    fill: none;
    stroke: currentColor;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .mobile-menu-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 44px;
    height: 44px;
    color: var(--text-main);
    border-radius: 50%;
    transition: var(--smooth-fast);
  }

  @media (min-width: 992px) {
    .mobile-menu-btn {
      display: none;
    }
  }

  .mobile-menu-btn svg {
    width: 24px;
    height: 24px;
    stroke: currentColor;
    stroke-width: 2;
    stroke-linecap: round;
  }

  /* ==========================================================================
     6. MOBILE DRAWER WITH STAGGERED ANIMATION
     ========================================================================== */
  .mobile-drawer-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    z-index: 999;
    opacity: 0;
    visibility: hidden;
    transition: var(--smooth);
  }

  .mobile-drawer-overlay.is-open {
    opacity: 1;
    visibility: visible;
  }

  .mobile-drawer {
    position: fixed;
    top: 0;
    right: -100%;
    width: 320px;
    max-width: 85vw;
    height: 100vh;
    background: var(--bg-surface);
    z-index: 1000;
    box-shadow: var(--shadow-lg);
    transition: right 0.5s cubic-bezier(0.25, 0.8, 0.25, 1);
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    overflow-y: auto;
  }

  .mobile-drawer.is-open {
    right: 0;
  }

  .drawer-header {
    display: flex;
    justify-content: flex-end;
    margin-bottom: var(--space-8);
  }

  .drawer-close-btn {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: var(--bg-surface-hover);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--text-main);
    transition: var(--smooth-fast);
  }
  
  .drawer-close-btn:hover {
    background: var(--color-primary-light);
    color: var(--color-primary);
  }

  .drawer-nav {
    display: flex;
    flex-direction: column;
    gap: var(--space-6);
  }

  .drawer-nav a {
    font-size: 1.5rem;
    font-weight: 700;
    color: var(--text-main);
    opacity: 0;
    transform: translateX(30px);
    transition: all 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
  }

  .drawer-nav a:hover {
    color: var(--color-primary);
  }

  .mobile-drawer.is-open .drawer-nav a {
    opacity: 1;
    transform: translateX(0);
  }

  .mobile-drawer.is-open .drawer-nav a:nth-child(1) { transition-delay: 0.1s; }
  .mobile-drawer.is-open .drawer-nav a:nth-child(2) { transition-delay: 0.15s; }
  .mobile-drawer.is-open .drawer-nav a:nth-child(3) { transition-delay: 0.2s; }
  .mobile-drawer.is-open .drawer-nav a:nth-child(4) { transition-delay: 0.25s; }
  .mobile-drawer.is-open .drawer-nav a:nth-child(5) { transition-delay: 0.3s; }

body.script:
    //
    document.addEventListener('DOMContentLoaded', () => {
      'use strict';

      /* Dark Mode Toggle */
      const darkModeBtn = document.getElementById('dark-mode-toggle');
      const htmlEl = document.documentElement;
      const sunIcon = document.querySelector('.sun-icon');
      const moonIcon = document.querySelector('.moon-icon');
      
      const setDarkMode = (isDark) => {
        if (isDark) {
          htmlEl.setAttribute('data-theme', 'dark');
          if (sunIcon) sunIcon.style.display = 'block';
          if (moonIcon) moonIcon.style.display = 'none';
          localStorage.setItem('theme', 'dark');
        } else {
          htmlEl.removeAttribute('data-theme');
          if (sunIcon) sunIcon.style.display = 'none';
          if (moonIcon) moonIcon.style.display = 'block';
          localStorage.setItem('theme', 'light');
        }
      };

      if (localStorage.getItem('theme') === 'dark' || (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        setDarkMode(true);
      }

      if (darkModeBtn) {
        darkModeBtn.addEventListener('click', () => {
          setDarkMode(htmlEl.getAttribute('data-theme') !== 'dark');
        });
      }

      /* Hero Typing Effect */
      const typingSpan = document.getElementById('hero-typing');
      if (typingSpan) {
        const phrases = ["UX/UI Designer", "Frontend Developer", "Tech Enthusiast", "Creative Creator"];
        let phraseIndex = 0;
        let charIndex = 0;
        let isDeleting = false;
        
        const typeEffect = () => {
          const currentPhrase = phrases[phraseIndex];
          
          if (isDeleting) {
            typingSpan.textContent = currentPhrase.substring(0, charIndex - 1);
            charIndex--;
          } else {
            typingSpan.textContent = currentPhrase.substring(0, charIndex + 1);
            charIndex++;
          }
          
          let speed = isDeleting ? 50 : 100;
          
          if (!isDeleting && charIndex === currentPhrase.length) {
            speed = 2000;
            isDeleting = true;
          } else if (isDeleting && charIndex === 0) {
            isDeleting = false;
            phraseIndex = (phraseIndex + 1) % phrases.length;
            speed = 500;
          }
          
          setTimeout(typeEffect, speed);
        };
        setTimeout(typeEffect, 1000);
      }

      /* Back to Top Logic */
      const backToTopBtn = document.getElementById('back-to-top');
      if (backToTopBtn) {
        window.addEventListener('scroll', () => {
          if (window.scrollY > 500) {
            backToTopBtn.classList.add('is-visible');
          } else {
            backToTopBtn.classList.remove('is-visible');
          }
        }, { passive: true });
        
        backToTopBtn.addEventListener('click', () => {
          window.scrollTo({ top: 0, behavior: 'smooth' });
        });
      }

      /* Engagement Buttons Interaction */
      const clapBtn = document.getElementById('clap-btn');
      if (clapBtn) {
        clapBtn.addEventListener('click', function() {
          this.classList.toggle('clapped');
          const countSpan = this.querySelector('.clap-count');
          if (countSpan) {
            if (this.classList.contains('clapped')) {
              countSpan.textContent = '1.2k + 1';
            } else {
              countSpan.textContent = '1.2k';
            }
          }
        });
      }

      const bookmarkBtn = document.getElementById('bookmark-btn');
      if (bookmarkBtn) {
        bookmarkBtn.addEventListener('click', function() {
          this.classList.toggle('bookmarked');
          if(this.classList.contains('bookmarked')) {
            this.style.color = 'var(--color-primary)';
            this.style.background = 'var(--color-primary-light)';
          } else {
            this.style.color = '';
            this.style.background = '';
          }
        });
      }

      /* Mobile Nav Logic */
      const menuBtn = document.getElementById('mobile-menu-btn');
      const closeBtn = document.getElementById('drawer-close-btn');
      const drawer = document.getElementById('mobile-drawer');
      const overlay = document.getElementById('mobile-drawer-overlay');
      const searchToggle = document.getElementById('search-toggle');
      const searchForm = document.getElementById('search-form');
      const searchInput = document.getElementById('search-input');
      const body = document.body;

      const toggleMenu = () => {
        if(drawer) {
          drawer.classList.toggle('is-open');
          if(overlay) overlay.classList.toggle('is-open');
          body.classList.toggle('no-scroll');
        }
      };

      if (menuBtn) menuBtn.addEventListener('click', toggleMenu);
      if (closeBtn) closeBtn.addEventListener('click', toggleMenu);
      if (overlay) overlay.addEventListener('click', toggleMenu);

      if (searchToggle && searchForm) {
        searchToggle.addEventListener('click', () => {
          searchForm.classList.toggle('is-expanded');
          if (searchForm.classList.contains('is-expanded')) {
            searchInput.focus();
          }
        });
      }

      /* Intersection Observer (Fade-In Scroll Animations) */
      const scrollObserver = new IntersectionObserver((entries, observer) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            entry.target.classList.add('visible', 'is-visible');
            observer.unobserve(entry.target); 
          }
        });
      }, { root: null, rootMargin: '0px 0px -50px 0px', threshold: 0.1 });

      document.querySelectorAll('.hidden-animate, .post-card, .widget, .floating-share').forEach(el => {
        scrollObserver.observe(el);
      });

      /* Dynamic Reading Progress Bar */
      const progressBar = document.createElement('div');
      progressBar.id = 'reading-progress-bar';
      Object.assign(progressBar.style, {
        position: 'fixed', top: '0', left: '0', width: '0%', height: '4px',
        backgroundColor: 'var(--color-primary, #3b82f6)', zIndex: '9999',
        transition: 'width 0.1s ease-out', pointerEvents: 'none'
      });
      document.body.appendChild(progressBar);

      /* Scroll Events (Smart Header, Progress Bar, Parallax) */
      const header = document.getElementById('site-header');
      let lastScrollY = window.scrollY;
      let ticking = false;

      window.addEventListener('scroll', () => {
        if (!ticking) {
          window.requestAnimationFrame(() => {
            const currentScrollY = window.scrollY || document.documentElement.scrollTop;
            const scrollHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
            
            // Progress Bar Update
            if (scrollHeight > 0) {
              progressBar.style.width = `${(currentScrollY / scrollHeight) * 100}%`;
            }

            // Smart Sticky Header Update
            if (header) {
              if (currentScrollY > lastScrollY) {
                if (currentScrollY > 100) {
                  header.classList.add('headroom--hidden');
                }
              } else {
                header.classList.remove('headroom--hidden');
              }
            }

            // Parallax Update (Using > to avoid strictly forbidden characters in XML)
            const parallaxImg = document.querySelector('.parallax-img');
            if (parallaxImg) {
              if (window.innerHeight > currentScrollY) {
                parallaxImg.style.transform = `translateY(${currentScrollY * 0.3}px)`;
              }
            }

            lastScrollY = currentScrollY;
            ticking = false;
          });
          ticking = true;
        }
      }, { passive: true });
      
    });
